# WebSocket server
def generate_handshake_key(key):
    """Generate WebSocket handshake key"""
    GUID = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
    key = key + GUID
    import hashlib
    hash = hashlib.sha1(key.encode()).digest()
    return ubinascii.b2a_base64(hash).decode().strip()

def parse_websocket_frame(data):
    """Parse WebSocket frame"""
    if len(data) < 2:
        return None
    
    # Parse header
    first_byte = data[0]
    second_byte = data[1]
    
    # Check if it's a close frame
    if (first_byte & 0x0F) == 8:
        return None
    
    # Check if it's a text frame
    if (first_byte & 0x0F) != 1:
        return None
    
    # Parse payload length
    payload_length = second_byte & 0x7F
    if payload_length == 126:
        payload_length = struct.unpack("!H", data[2:4])[0]
        offset = 4
    elif payload_length == 127:
        payload_length = struct.unpack("!Q", data[2:10])[0]
        offset = 10
    else:
        offset = 2
    
    # Parse mask
    mask = data[offset:offset+4]
    offset += 4
    
    # Parse payload
    payload = data[offset:offset+payload_length]
    
    # Unmask payload
    unmasked = bytearray()
    for i in range(len(payload)):
        unmasked.append(payload[i] ^ mask[i % 4])
    
    return unmasked.decode('utf-8')

def create_websocket_frame(message):
    """Create WebSocket frame"""
    message_bytes = message.encode('utf-8')
    length = len(message_bytes)
    
    # Create header
    header = bytearray()
    header.append(0x81)  # Text frame
    
    if length <= 125:
        header.append(length)
    elif length <= 65535:
        header.append(126)
        header.extend(struct.pack("!H", length))
    else:
        header.append(127)
        header.extend(struct.pack("!Q", length))
    
    return bytes(header) + message_bytes

